useOAuth:
/**
 * React hook for OAuth with property-based access
 *
 * Single entry point for all OAuth operations.
 * Uses selectors internally to prevent unnecessary re-renders.
 *
 * **Property-based access (clean and simple):**
 * ```typescript
 * // ✅ State from store (reactive, re-renders on change)
 * const status = useOAuth('status');
 * const error = useOAuth('error');
 * const partners = useOAuth('partners');
 * const connectedPartners = useOAuth('connectedPartners');
 * const isAvailable = useOAuth('isAvailable');
 *
 * // ✅ Methods (stable, never re-renders)
 * const connect = useOAuth('connect');
 * await connect('github');
 * await connect('github', { purpose: 'api-access', scopes: ['repo', 'user:email'] });
 * const disconnect = useOAuth('disconnect');
 * const handleCallback = useOAuth('handleCallback');
 * const isConnected = useOAuth('isConnected');
 * const getCredentials = useOAuth('getCredentials');
 * ```
 *
 * **How it works:**
 * - Store properties (status, error, partners, connectedPartners) → Subscribe via Zustand (reactive)
 * - Methods (connect, disconnect, handleCallback, isConnected, getCredentials) → useCallback (stable)
 *
 * @template K - The property key from OAuthAPI
 * @param key - Property name to access
 * @returns The value of the specified property
 *
 * @version 0.1.0
 * @since 0.0.1
 * @author AMBROISE PARK Consulting
 */
export declare function useOAuth<K extends keyof OAuthAPI>(key: K): OAuthAPI[K];

MultipleOAuthProvidersProps:
/**
 * Props for the MultipleOAuthProviders component
 */
export interface MultipleOAuthProvidersProps {
    /** OAuth providers to display (defaults to auto-discovered enabled providers) */
    providers?: OAuthPartnerId[];
    /** Purpose for OAuth connections */
    purpose?: OAuthPurpose;
    /** CSS class for the container element */
    containerClassName?: string;
    /** CSS class for each provider button */
    providerClassName?: string;
    /** Button variant to use */
    variant?: ButtonVariant;
    /** Layout of the provider buttons */
    layout?: 'vertical' | 'horizontal' | 'grid';
    /** Whether to show text labels on buttons */
    showLabels?: boolean;
    /** Accessible label for the OAuth providers region */
    ariaLabel?: string;
    /** ID for the component (auto-generated if not provided) */
    id?: string;
    /** Whether buttons should take full width of their container */
    fullWidth?: boolean;
    /** Callbacks */
    onSuccess?: (result: any) => void;
    onError?: (error: Error) => void;
}

OAuthConnectionModalProps:
/** Props for the OAuthConnectionModal component. */
export interface OAuthConnectionModalProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    /** Purpose for OAuth connections */
    purpose?: 'api-access' | 'authentication';
    /** Optional title override */
    title?: string;
    /** Optional description override */
    description?: string;
}

OAuthFallbackProps:
/** Props for the OAuthFallback component. */
export interface OAuthFallbackProps {
    /** Custom message to display */
    message?: string;
    /** Whether to show a connect button (will be disabled) */
    showConnectButton?: boolean;
    /** Custom CSS class */
    className?: string;
}

OAuthPartnerButtonProps:
/** Props for the OAuthPartnerButton component. */
export interface OAuthPartnerButtonProps {
    partnerId: OAuthPartnerId;
    purpose?: OAuthPurpose;
    onSuccess?: (result: any) => void;
    onOAuthError?: (error: Error) => void;
    className?: string;
    children?: React.ReactNode;
    disabled?: boolean;
    display?: (typeof DISPLAY)[keyof typeof DISPLAY];
    style?: CSSProperties;
}
